import type { ComponentProps } from 'react';
import { Autocomplete as AutocompletePrimitive } from '@base-ui/react/autocomplete';
import { Dialog as DialogPrimitive } from '@base-ui/react/dialog';
import { clsx } from 'clsx';
import { createContext, useContext, useEffect, useMemo } from 'react';
import { CloseIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './CommandPalette.module.css';

const createCommandPaletteHandle = DialogPrimitive.createHandle;

const CommandPaletteContext = createContext<{
  handle: DialogPrimitive.Handle<unknown>;
  modal: DialogPrimitive.Root.Props['modal'];
} | null>(null);

function useCommandPaletteContext(componentName: string) {
  const context = useContext(CommandPaletteContext);

  if (!context) {
    throw new Error(`${componentName} must be used within CommandPalette.`);
  }

  return context;
}

function isMacLikePlatform() {
  if (typeof navigator === 'undefined') {
    return false;
  }

  const platform =
    (navigator as Navigator & { userAgentData?: { platform?: string } }).userAgentData?.platform ??
    navigator.platform;
  return /mac|iphone|ipad|ipod/i.test(platform);
}

function isShortcutMatch(event: KeyboardEvent, shortcut: string) {
  const parts = shortcut
    .toLowerCase()
    .split('+')
    .map((part) => part.trim())
    .filter(Boolean);
  const key = parts.at(-1);
  const primaryModifier = parts.includes('mod') ? (isMacLikePlatform() ? 'meta' : 'ctrl') : null;
  const needsCtrl =
    parts.includes('ctrl') || parts.includes('control') || primaryModifier === 'ctrl';
  const needsMeta =
    parts.includes('meta') ||
    parts.includes('cmd') ||
    parts.includes('command') ||
    primaryModifier === 'meta';
  const needsAlt = parts.includes('alt') || parts.includes('option');
  const needsShift = parts.includes('shift');
  const eventKey = event.key.toLowerCase();
  const eventCode =
    event.code.startsWith('Key') || event.code.startsWith('Digit')
      ? event.code.slice(event.code.startsWith('Key') ? 3 : 5).toLowerCase()
      : event.code.toLowerCase();

  if (!key || (eventKey !== key && eventCode !== key)) {
    return false;
  }

  return (
    event.ctrlKey === needsCtrl &&
    event.metaKey === needsMeta &&
    event.altKey === needsAlt &&
    event.shiftKey === needsShift
  );
}

function isEditableTarget(target: EventTarget | null) {
  if (!(target instanceof Element)) {
    return false;
  }

  return (
    target.closest('input, textarea, select, [contenteditable], [contenteditable="true"]') !== null
  );
}

// AutocompletePrimitive.Root has two overloads: one for grouped items and one for flat items.
// TypeScript requires a type guard to resolve the correct overload signature; both branches
// inside CommandPaletteContent are functionally identical at runtime.
function isGroupedItems<ItemValue>(
  items: readonly ItemValue[] | readonly { items: readonly unknown[] }[] | undefined,
): items is readonly { items: readonly unknown[] }[] {
  return Boolean(
    items?.[0] && typeof items[0] === 'object' && items[0] !== null && 'items' in items[0],
  );
}

function CommandPalette<Payload = unknown>({
  modal = true,
  shortcut = 'mod+k',
  shortcutTarget,
  handle,
  children,
  ...props
}: DialogPrimitive.Root.Props<Payload> & {
  shortcut?: false | string;
  shortcutTarget?: Document | HTMLElement | null;
}) {
  const fallbackHandle = useMemo(() => createCommandPaletteHandle<Payload>(), []);
  const resolvedHandle = handle ?? fallbackHandle;

  useEffect(() => {
    if (shortcut === false || shortcutTarget === null) {
      return;
    }

    const target = shortcutTarget ?? document;
    const handleKeyDown = (event: KeyboardEvent) => {
      if (
        event.defaultPrevented ||
        event.isComposing ||
        isEditableTarget(event.target) ||
        !isShortcutMatch(event, shortcut)
      ) {
        return;
      }

      event.preventDefault();
      resolvedHandle.open(null);
    };

    const eventListener = handleKeyDown as EventListener;
    target.addEventListener('keydown', eventListener);
    return () => target.removeEventListener('keydown', eventListener);
  }, [resolvedHandle, shortcut, shortcutTarget]);

  return (
    <CommandPaletteContext.Provider value={{ handle: resolvedHandle, modal }}>
      <DialogPrimitive.Root modal={modal} handle={resolvedHandle} {...props}>
        {children}
      </DialogPrimitive.Root>
    </CommandPaletteContext.Provider>
  );
}

function CommandPaletteTrigger({ className, render, ...props }: DialogPrimitive.Trigger.Props) {
  return (
    <DialogPrimitive.Trigger
      data-slot="command-palette-trigger"
      className={render ? className : mergeClassName(className, styles.trigger)}
      render={render}
      {...props}
    />
  );
}

function CommandPalettePortal(props: DialogPrimitive.Portal.Props) {
  return <DialogPrimitive.Portal {...props} />;
}

function CommandPaletteBackdrop({ className, ...props }: DialogPrimitive.Backdrop.Props) {
  return (
    <DialogPrimitive.Backdrop
      data-slot="command-palette-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function CommandPaletteViewport({ className, ...props }: DialogPrimitive.Viewport.Props) {
  return (
    <DialogPrimitive.Viewport
      data-slot="command-palette-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function CommandPalettePopup({ className, ...props }: DialogPrimitive.Popup.Props) {
  return (
    <DialogPrimitive.Popup
      data-slot="command-palette-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function CommandPaletteClose({ className, ...props }: DialogPrimitive.Close.Props) {
  return (
    <DialogPrimitive.Close
      data-slot="command-palette-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    />
  );
}

function CommandPaletteContent<ItemValue = unknown>({
  className,
  children,
  items,
  itemToStringValue,
  value,
  defaultValue,
  onValueChange,
  filter,
  filteredItems,
  limit,
  ...props
}: DialogPrimitive.Popup.Props & {
  items?: AutocompletePrimitive.Root.Props<ItemValue>['items'];
  itemToStringValue?: AutocompletePrimitive.Root.Props<ItemValue>['itemToStringValue'];
  value?: AutocompletePrimitive.Root.Props<ItemValue>['value'];
  defaultValue?: AutocompletePrimitive.Root.Props<ItemValue>['defaultValue'];
  onValueChange?: AutocompletePrimitive.Root.Props<ItemValue>['onValueChange'];
  filter?: AutocompletePrimitive.Root.Props<ItemValue>['filter'];
  filteredItems?: AutocompletePrimitive.Root.Props<ItemValue>['filteredItems'];
  limit?: AutocompletePrimitive.Root.Props<ItemValue>['limit'];
}) {
  const { modal } = useCommandPaletteContext('CommandPaletteContent');
  const autocompleteProps = {
    autoHighlight: 'always' as const,
    defaultValue,
    filter,
    filteredItems,
    inline: true,
    itemToStringValue,
    keepHighlight: true,
    limit,
    onValueChange,
    open: true,
    value,
  };

  return (
    <CommandPalettePortal>
      {modal === true ? <CommandPaletteBackdrop /> : null}
      <CommandPaletteViewport className={modal === true ? undefined : styles.viewportNonModal}>
        <CommandPalettePopup className={className} {...props}>
          {isGroupedItems(items) ? (
            <AutocompletePrimitive.Root {...autocompleteProps} items={items}>
              {children}
            </AutocompletePrimitive.Root>
          ) : (
            <AutocompletePrimitive.Root {...autocompleteProps} items={items}>
              {children}
            </AutocompletePrimitive.Root>
          )}
        </CommandPalettePopup>
      </CommandPaletteViewport>
    </CommandPalettePortal>
  );
}

function CommandPaletteInputWrap({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div
      data-slot="command-palette-input-wrap"
      className={clsx(styles.inputWrap, className)}
      {...props}
    />
  );
}

function CommandPaletteInput({ className, ...props }: AutocompletePrimitive.Input.Props) {
  return (
    <AutocompletePrimitive.Input
      data-slot="command-palette-input"
      className={mergeClassName(className, styles.input)}
      {...props}
    />
  );
}

function CommandPaletteClear({ className, children, ...props }: AutocompletePrimitive.Clear.Props) {
  return (
    <AutocompletePrimitive.Clear
      data-slot="command-palette-clear"
      className={mergeClassName(className, styles.clear)}
      {...props}
    >
      {children ?? <CloseIcon className={styles.iconSvg} />}
    </AutocompletePrimitive.Clear>
  );
}

function CommandPaletteStatus({ className, ...props }: AutocompletePrimitive.Status.Props) {
  return (
    <AutocompletePrimitive.Status
      data-slot="command-palette-status"
      className={mergeClassName(className, styles.status)}
      {...props}
    />
  );
}

function CommandPaletteEmpty({ className, ...props }: AutocompletePrimitive.Empty.Props) {
  return (
    <AutocompletePrimitive.Empty
      data-slot="command-palette-empty"
      className={mergeClassName(className, styles.empty)}
      {...props}
    />
  );
}

function CommandPaletteList({ className, ...props }: AutocompletePrimitive.List.Props) {
  return (
    <AutocompletePrimitive.List
      data-slot="command-palette-list"
      className={mergeClassName(className, styles.list)}
      {...props}
    />
  );
}

function CommandPaletteGroup({ className, ...props }: AutocompletePrimitive.Group.Props) {
  return (
    <AutocompletePrimitive.Group
      data-slot="command-palette-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function CommandPaletteGroupLabel({ className, ...props }: AutocompletePrimitive.GroupLabel.Props) {
  return (
    <AutocompletePrimitive.GroupLabel
      data-slot="command-palette-group-label"
      className={mergeClassName(className, styles.groupLabel)}
      {...props}
    />
  );
}

function CommandPaletteCollection(props: AutocompletePrimitive.Collection.Props) {
  return <AutocompletePrimitive.Collection data-slot="command-palette-collection" {...props} />;
}

function CommandPaletteItem({
  className,
  closeOnSelect = true,
  onClick,
  ...props
}: AutocompletePrimitive.Item.Props & {
  closeOnSelect?: boolean;
}) {
  const { handle } = useCommandPaletteContext('CommandPaletteItem');

  const handleClick: AutocompletePrimitive.Item.Props['onClick'] = (event) => {
    onClick?.(event);

    if (!event.defaultPrevented && closeOnSelect) {
      handle.close();
    }
  };

  return (
    <AutocompletePrimitive.Item
      data-slot="command-palette-item"
      className={mergeClassName(className, styles.item)}
      onClick={handleClick}
      {...props}
    />
  );
}

function CommandPaletteItemIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="command-palette-item-icon"
      className={clsx(styles.itemIcon, className)}
      {...props}
    />
  );
}

function CommandPaletteItemText({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="command-palette-item-text"
      className={clsx(styles.itemText, className)}
      {...props}
    />
  );
}

function CommandPaletteItemLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="command-palette-item-label"
      className={clsx(styles.itemLabel, className)}
      {...props}
    />
  );
}

function CommandPaletteItemDescription({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="command-palette-item-description"
      className={clsx(styles.itemDescription, className)}
      {...props}
    />
  );
}

function CommandPaletteItemMeta({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="command-palette-item-meta"
      className={clsx(styles.itemMeta, className)}
      {...props}
    />
  );
}

function CommandPaletteSeparator({ className, ...props }: AutocompletePrimitive.Separator.Props) {
  return (
    <AutocompletePrimitive.Separator
      data-slot="command-palette-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
}

function CommandPaletteFooter({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="command-palette-footer" className={clsx(styles.footer, className)} {...props} />
  );
}

function CommandPaletteKbd({ className, ...props }: ComponentProps<'kbd'>) {
  return <kbd data-slot="command-palette-kbd" className={clsx(styles.kbd, className)} {...props} />;
}

export {
  CommandPalette,
  createCommandPaletteHandle,
  CommandPaletteTrigger,
  CommandPalettePortal,
  CommandPaletteBackdrop,
  CommandPaletteViewport,
  CommandPalettePopup,
  CommandPaletteClose,
  CommandPaletteContent,
  CommandPaletteInputWrap,
  CommandPaletteInput,
  CommandPaletteClear,
  CommandPaletteStatus,
  CommandPaletteEmpty,
  CommandPaletteList,
  CommandPaletteGroup,
  CommandPaletteGroupLabel,
  CommandPaletteCollection,
  CommandPaletteItem,
  CommandPaletteItemIcon,
  CommandPaletteItemText,
  CommandPaletteItemLabel,
  CommandPaletteItemDescription,
  CommandPaletteItemMeta,
  CommandPaletteSeparator,
  CommandPaletteFooter,
  CommandPaletteKbd,
};

@layer ui.components {
  .close {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin: 0;
    padding: 0;
    border: 0;
    background: transparent;
    color: inherit;
    cursor: pointer;
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--command-palette-trigger-gap, var(--spacing-2));
    min-height: var(--command-palette-trigger-height, var(--size-lg));
    margin: 0;
    padding: var(--command-palette-trigger-padding-y, 0.5rem)
      var(--command-palette-trigger-padding-x, 0.875rem);
    border: var(--command-palette-trigger-border-width, var(--border-width-sm)) solid
      var(--command-palette-trigger-border-color, var(--color-border));
    border-radius: var(--command-palette-trigger-radius, var(--radius-md));
    background-color: var(--command-palette-trigger-bg, var(--color-background));
    color: var(--command-palette-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--command-palette-trigger-font-size, var(--text-md));
    line-height: var(--command-palette-trigger-line-height, var(--line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--command-palette-trigger-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(--command-palette-focus-ring-width, var(--border-width-sm)) solid
        var(--command-palette-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--command-palette-focus-ring-width, var(--border-width-sm)) * -1);
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--command-palette-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--command-palette-backdrop-blur, 4px)));
    transition:
      opacity var(--command-palette-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--command-palette-backdrop-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  .viewport {
    box-sizing: border-box;
    position: fixed;
    z-index: var(--z-modal);
    inset: 0;
    display: grid;
    align-items: start;
    justify-items: center;
    overflow-y: auto;
    overscroll-behavior: contain;
    padding: var(--command-palette-viewport-padding, 10dvh var(--spacing-4) var(--spacing-4));
  }

  .viewportNonModal {
    pointer-events: none;
  }

  .popup {
    box-sizing: border-box;
    position: relative;
    display: flex;
    width: min(
      var(--command-palette-width, 37.5rem),
      var(--command-palette-max-width, calc(100vw - var(--spacing-8, 2rem))),
      var(--available-width, calc(100vw - var(--spacing-8, 2rem)))
    );
    max-height: min(var(--command-palette-max-height, 34rem), calc(100dvh - 5rem));
    flex-direction: column;
    overflow: hidden;
    border: var(--command-palette-border-width, var(--border-width-sm)) solid
      var(--command-palette-border-color, color-mix(in oklab, var(--color-border) 84%, transparent));
    border-radius: var(--command-palette-radius, var(--radius-lg));
    background: linear-gradient(
      180deg,
      var(--command-palette-top-bg, color-mix(in oklab, var(--color-popover) 96%, white 4%)),
      var(--command-palette-bg, var(--color-popover)) 7rem
    );
    pointer-events: auto;
    color: var(--command-palette-color, var(--color-popover-foreground));
    box-shadow: var(--command-palette-shadow, var(--shadow-lg));
    transform-origin: top center;
    transition:
      opacity var(--command-palette-transition, var(--transition-default)),
      transform var(--command-palette-transition, var(--transition-default)),
      translate var(--command-palette-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      translate: 0 -0.75rem;
      transform: scale(var(--command-palette-scale, var(--scale-popup)));
    }
  }

  .inputWrap {
    box-sizing: border-box;
    position: relative;
    display: flex;
    align-items: center;
    gap: var(--command-palette-input-gap, var(--spacing-2));
    min-height: var(--command-palette-input-height, 4rem);
    padding: var(--command-palette-input-wrap-padding-y, var(--spacing-3))
      var(--command-palette-input-wrap-padding-x, var(--spacing-4));
    border-bottom: var(--command-palette-divider-width, var(--border-width-sm)) solid
      var(--command-palette-divider-color, var(--color-border));
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    height: var(--command-palette-input-control-height, 2.25rem);
    margin: 0;
    border: 0;
    padding: 0;
    background: transparent;
    color: inherit;
    font: inherit;
    font-size: var(--command-palette-input-font-size, var(--text-lg));
    line-height: var(--command-palette-input-line-height, var(--line-height-text-lg));
    outline: 0;

    &::placeholder {
      color: var(--command-palette-input-placeholder-color, var(--color-muted-foreground));
    }
  }

  .clear {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--command-palette-clear-size, 1.75rem);
    height: var(--command-palette-clear-size, 1.75rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--command-palette-clear-radius, var(--radius-md));
    padding: 0;
    background: transparent;
    color: var(--command-palette-muted-color, var(--color-muted-foreground));
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      color var(--transition-default);

    &:hover {
      background-color: var(--command-palette-clear-bg-hover, var(--color-accent));
      color: var(--command-palette-color, var(--color-popover-foreground));
    }

    &:focus-visible {
      outline: var(--command-palette-focus-ring-width, var(--border-width-sm)) solid
        var(--command-palette-focus-ring-color, var(--color-ring));
      outline-offset: var(--command-palette-focus-ring-offset, var(--border-width-sm));
    }
  }

  .iconSvg {
    width: var(--command-palette-icon-size, 1rem);
    height: var(--command-palette-icon-size, 1rem);
  }

  .status {
    margin: 0;
    padding: 0;

    &:not(:empty) {
      padding: var(--command-palette-status-padding-y, 0.25rem)
        var(--command-palette-status-padding-x, var(--spacing-4));
      color: var(--command-palette-muted-color, var(--color-muted-foreground));
      font-size: var(--command-palette-status-font-size, var(--text-xs));
      line-height: var(--command-palette-status-line-height, var(--line-height-text-xs));
    }
  }

  .empty {
    margin: 0;
    padding: 0;

    &:not(:empty) {
      padding: var(--command-palette-empty-padding-y, 0.75rem)
        var(--command-palette-empty-padding-x, var(--spacing-4));
      color: var(--command-palette-muted-color, var(--color-muted-foreground));
      font-size: var(--command-palette-empty-font-size, var(--text-sm));
      line-height: var(--command-palette-empty-line-height, var(--line-height-text-sm));
    }
  }

  .list {
    box-sizing: border-box;
    flex: 1 1 auto;
    min-height: 0;
    overflow-y: auto;
    overscroll-behavior: contain;
    padding: var(--command-palette-list-padding-y, var(--spacing-2))
      var(--command-palette-list-padding-x, var(--spacing-2));
    scroll-padding-block: var(--command-palette-list-scroll-padding-y, var(--spacing-2));
    outline: 0;

    &[data-empty] {
      padding: 0;
    }
  }

  .group {
    display: grid;
    gap: var(--command-palette-group-gap, 0.125rem);

    &:not(:last-child) {
      padding-bottom: var(--command-palette-group-padding-bottom, var(--spacing-2));
    }
  }

  .groupLabel {
    position: sticky;
    top: calc(var(--command-palette-list-padding-y, var(--spacing-2)) * -1);
    z-index: 1;
    display: block;
    margin: 0;
    padding: var(--command-palette-group-label-padding-y, 0.375rem)
      var(--command-palette-group-label-padding-x, 0.75rem);
    background-color: var(--command-palette-bg, var(--color-popover));
    color: var(--command-palette-muted-color, var(--color-muted-foreground));
    font-size: var(--command-palette-group-label-font-size, var(--text-xs));
    font-weight: var(--command-palette-group-label-font-weight, var(--weight-semibold));
    line-height: var(--command-palette-group-label-line-height, var(--line-height-text-xs));
  }

  .item {
    box-sizing: border-box;
    position: relative;
    z-index: 0;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr) auto;
    align-items: center;
    gap: var(--command-palette-item-gap, var(--spacing-3));
    min-height: var(--command-palette-item-min-height, 3rem);
    padding: var(--command-palette-item-padding-y, 0.5rem)
      var(--command-palette-item-padding-x, 0.75rem);
    border-radius: var(--command-palette-item-radius, var(--radius-md));
    color: var(--command-palette-item-color, var(--command-palette-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--command-palette-item-font-size, var(--text-sm));
    line-height: var(--command-palette-item-line-height, var(--line-height-text-sm));
    outline: 0;
    cursor: default;
    user-select: none;

    &[data-highlighted] {
      color: var(--command-palette-highlight-color, var(--color-foreground));
    }

    &[data-highlighted]::before {
      content: '';
      position: absolute;
      z-index: -1;
      inset: 0;
      border-radius: inherit;
      background-color: var(--command-palette-highlight-bg, var(--color-accent));
    }

    &[data-disabled] {
      opacity: var(--opacity-disabled);
      pointer-events: none;
    }
  }

  .itemIcon {
    display: inline-flex;
    width: var(--command-palette-item-icon-box-size, 2rem);
    height: var(--command-palette-item-icon-box-size, 2rem);
    align-items: center;
    justify-content: center;
    border: var(--command-palette-item-icon-border-width, var(--border-width-sm)) solid
      var(--command-palette-item-icon-border-color, var(--color-border));
    border-radius: var(--command-palette-item-icon-radius, var(--radius-md));
    background-color: var(--command-palette-item-icon-bg, var(--color-muted));
    color: var(--command-palette-item-icon-color, var(--color-muted-foreground));

    & > svg {
      width: var(--command-palette-item-icon-size, 1rem);
      height: var(--command-palette-item-icon-size, 1rem);
    }
  }

  .itemText {
    display: grid;
    min-width: 0;
    gap: var(--command-palette-item-text-gap, 0.125rem);
  }

  .itemLabel,
  .itemDescription {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemLabel {
    font-weight: var(--command-palette-item-label-font-weight, var(--weight-medium));
  }

  .itemDescription {
    color: var(--command-palette-muted-color, var(--color-muted-foreground));
    font-size: var(--command-palette-item-description-font-size, var(--text-xs));
    line-height: var(--command-palette-item-description-line-height, var(--line-height-text-xs));
  }

  .itemMeta {
    color: var(--command-palette-muted-color, var(--color-muted-foreground));
    font-size: var(--command-palette-item-meta-font-size, var(--text-xs));
    line-height: var(--command-palette-item-meta-line-height, var(--line-height-text-xs));
    white-space: nowrap;
  }

  .separator {
    height: var(--command-palette-divider-width, var(--border-width-sm));
    margin: var(--command-palette-separator-margin-y, var(--spacing-2))
      var(--command-palette-separator-margin-x, var(--spacing-2));
    background-color: var(--command-palette-divider-color, var(--color-border));
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--command-palette-footer-gap, var(--spacing-3));
    padding: var(--command-palette-footer-padding-y, 0.625rem)
      var(--command-palette-footer-padding-x, var(--spacing-4));
    border-top: var(--command-palette-divider-width, var(--border-width-sm)) solid
      var(--command-palette-divider-color, var(--color-border));
    color: var(--command-palette-muted-color, var(--color-muted-foreground));
    font-size: var(--command-palette-footer-font-size, var(--text-xs));
    line-height: var(--command-palette-footer-line-height, var(--line-height-text-xs));
  }

  .kbd {
    box-sizing: border-box;
    display: inline-flex;
    min-width: var(--command-palette-kbd-min-width, 1.25rem);
    height: var(--command-palette-kbd-height, 1.25rem);
    align-items: center;
    justify-content: center;
    border: var(--command-palette-kbd-border-width, var(--border-width-sm)) solid
      var(--command-palette-kbd-border-color, var(--color-border));
    border-radius: var(--command-palette-kbd-radius, var(--radius-sm));
    padding-inline: var(--command-palette-kbd-padding-x, 0.375rem);
    background-color: var(--command-palette-kbd-bg, var(--color-muted));
    color: var(--command-palette-kbd-color, var(--color-muted-foreground));
    font-family: var(--command-palette-kbd-font-family, var(--font-mono));
    font-size: var(--command-palette-kbd-font-size, 0.6875rem);
    line-height: var(--command-palette-kbd-line-height, 1rem);
    white-space: nowrap;
  }
}
